    @WebMethod(operationName = "processPayment")
    public PaymentResponse processPayment(
            @WebParam(name = "paymentRequest") PaymentRequest request) {

        PaymentResponse response = new PaymentResponse();

        try {
            if (request == null) {
                response.setStatus("FAILED");
                response.setMessage("Payment request is null");
                response.setTransactionId(null);
                return response;
            }

            if (request.getAmount() <= 0) {
                response.setStatus("FAILED");
                response.setMessage("Invalid payment amount: must be greater than zero");
                response.setTransactionId(null);
                return response;
            }

            if (request.getCardNumber() == null || request.getCardNumber().trim().isEmpty()) {
                response.setStatus("FAILED");
                response.setMessage("Card number is required");
                response.setTransactionId(null);
                return response;
            }

            if (!isValidCardNumber(request.getCardNumber())) {
                response.setStatus("FAILED");
                response.setMessage("Invalid card number");
                response.setTransactionId(null);
                return response;
            }

            String transactionId = UUID.randomUUID().toString();

            PaymentRecord record = new PaymentRecord();
            record.setTransactionId(transactionId);
            record.setMerchantId(request.getMerchantId());
            record.setAmount(request.getAmount());
            record.setCurrency(request.getCurrency());
            record.setCardNumberMasked(maskCardNumber(request.getCardNumber()));
            record.setTimestamp(new Date());
            record.setStatus("APPROVED");

            paymentStore.put(transactionId, record);

            response.setStatus("APPROVED");
            response.setTransactionId(transactionId);
            response.setMessage("Payment processed successfully");
            response.setAmount(request.getAmount());
            response.setCurrency(request.getCurrency());

            System.out.println("Payment processed: " + transactionId + " | Amount: "
                    + request.getAmount() + " " + request.getCurrency());

        } catch (Exception e) {
            response.setStatus("ERROR");
            response.setMessage("Internal error: " + e.getMessage());
            response.setTransactionId(null);
        }

        return response;
    }

    @WebMethod(operationName = "refundPayment")
    public PaymentResponse refundPayment(
            @WebParam(name = "transactionId") String transactionId,
            @WebParam(name = "amount") double amount) {

        PaymentResponse response = new PaymentResponse();

        PaymentRecord original = paymentStore.get(transactionId);
        if (original == null) {
            response.setStatus("FAILED");
            response.setMessage("Original transaction not found: " + transactionId);
            return response;
        }

        if (amount > original.getAmount()) {
            response.setStatus("FAILED");
            response.setMessage("Refund amount exceeds original transaction amount");
            return response;
        }

        String refundId = "REFUND-" + UUID.randomUUID().toString();
        PaymentRecord refundRecord = new PaymentRecord();
        refundRecord.setTransactionId(refundId);
        refundRecord.setMerchantId(original.getMerchantId());
        refundRecord.setAmount(amount);
        refundRecord.setCurrency(original.getCurrency());
        refundRecord.setCardNumberMasked(original.getCardNumberMasked());
        refundRecord.setTimestamp(new Date());
        refundRecord.setStatus("REFUNDED");

        paymentStore.put(refundId, refundRecord);

        response.setStatus("REFUNDED");
        response.setTransactionId(refundId);
        response.setMessage("Refund processed successfully for original transaction: " + transactionId);
        response.setAmount(amount);
        response.setCurrency(original.getCurrency());

        return response;
    }

    @WebMethod(operationName = "getTransactionStatus")
    public PaymentResponse getTransactionStatus(
            @WebParam(name = "transactionId") String transactionId) {

        PaymentResponse response = new PaymentResponse();
        PaymentRecord record = paymentStore.get(transactionId);

        if (record == null) {
            response.setStatus("NOT_FOUND");
            response.setMessage("Transaction not found: " + transactionId);
            return response;
        }

        response.setStatus(record.getStatus());
        response.setTransactionId(record.getTransactionId());
        response.setAmount(record.getAmount());
        response.setCurrency(record.getCurrency());
        response.setMessage("Transaction found");

        return response;
    }

    private boolean isValidCardNumber(String cardNumber) {
        String sanitized = cardNumber.replaceAll("[\\s-]", "");
        if (sanitized.length() < 13 || sanitized.length() > 19) {
            return false;
        }
        // Luhn algorithm
        int sum = 0;
        boolean alternate = false;
        for (int i = sanitized.length() - 1; i >= 0; i--) {
            int n = Character.getNumericValue(sanitized.charAt(i));
            if (n < 0 || n > 9) return false;
            if (alternate) {
                n *= 2;
                if (n > 9) n -= 9;
            }
            sum += n;
            alternate = !alternate;
        }
        return (sum % 10 == 0);
    }

    private String maskCardNumber(String cardNumber) {
        String sanitized = cardNumber.replaceAll("[\\s-]", "");
        if (sanitized.length() <= 4) return "****";
        return "****-****-****-" + sanitized.substring(sanitized.length() - 4);
    }

