    // --- WS-Security Timestamp Handler ---

    public static class WsSecurityTimestampHandler implements SOAPHandler<SOAPMessageContext> {

        private static final String WSS_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
        private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
        private static final long TIMESTAMP_TOLERANCE_MS = 300_000; // 5 minutes
        private static final int MAX_NONCE_CACHE_SIZE = 10_000;

        private static final Set<String> processedTimestamps = Collections.newSetFromMap(new ConcurrentHashMap<>());
        private static final ConcurrentLinkedQueue<String> timestampQueue = new ConcurrentLinkedQueue<>();

        private static final SimpleDateFormat ISO_FORMAT = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
        private static final SimpleDateFormat ISO_FORMAT_NO_MILLIS = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss'Z'");

        static {
            ISO_FORMAT.setTimeZone(TimeZone.getTimeZone("UTC"));
            ISO_FORMAT_NO_MILLIS.setTimeZone(TimeZone.getTimeZone("UTC"));
        }

        @Override
        public Set<QName> getHeaders() {
            Set<QName> headers = new HashSet<>();
            headers.add(new QName(WSS_NS, "Security"));
            return headers;
        }

        @Override
        public boolean handleMessage(SOAPMessageContext context) {
            Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

            if (outbound != null && outbound) {
                return addTimestampToOutbound(context);
            } else {
                return validateInboundTimestamp(context);
            }
        }

        private boolean addTimestampToOutbound(SOAPMessageContext context) {
            try {
                SOAPMessage message = context.getMessage();
                SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
                SOAPHeader header = envelope.getHeader();

                if (header == null) {
                    header = envelope.addHeader();
                }

                SOAPElement securityElement = header.addChildElement("Security", "wsse", WSS_NS);
                securityElement.addAttribute(
                        envelope.createName("mustUnderstand", "soap",
                                "http://schemas.xmlsoap.org/soap/envelope/"), "1");

                SOAPElement timestampElement = securityElement.addChildElement("Timestamp", "wsu", WSU_NS);

                String timestampId = "TS-" + UUID.randomUUID().toString();
                timestampElement.addAttribute(
                        envelope.createName("Id", "wsu", WSU_NS), timestampId);

                Date now = new Date();
                Date expires = new Date(now.getTime() + TIMESTAMP_TOLERANCE_MS);

                SOAPElement createdElement = timestampElement.addChildElement("Created", "wsu", WSU_NS);
                synchronized (ISO_FORMAT) {
                    createdElement.addTextNode(ISO_FORMAT.format(now));
                }

                SOAPElement expiresElement = timestampElement.addChildElement("Expires", "wsu", WSU_NS);
                synchronized (ISO_FORMAT) {
                    expiresElement.addTextNode(ISO_FORMAT.format(expires));
                }

                message.saveChanges();
                System.out.println("WS-Security Timestamp added to outbound message: " + timestampId);
                return true;

            } catch (SOAPException e) {
                System.err.println("Error adding WS-Security timestamp: " + e.getMessage());
                return false;
            }
        }

        private boolean validateInboundTimestamp(SOAPMessageContext context) {
            try {
                SOAPMessage message = context.getMessage();
                SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
                SOAPHeader header = envelope.getHeader();

                if (header == null) {
                    System.err.println("WS-Security: No SOAP header found - rejecting message");
                    generateSOAPFault(context, "Missing WS-Security header");
                    return false;
                }

                Iterator<?> securityHeaders = header.getChildElements(new QName(WSS_NS, "Security"));
                if (!securityHeaders.hasNext()) {
                    System.err.println("WS-Security: No Security element found - rejecting message");
                    generateSOAPFault(context, "Missing WS-Security Security element");
                    return false;
                }

                SOAPElement securityElement = (SOAPElement) securityHeaders.next();
                Iterator<?> timestamps = securityElement.getChildElements(new QName(WSU_NS, "Timestamp"));

                if (!timestamps.hasNext()) {
                    System.err.println("WS-Security: No Timestamp element found - rejecting message");
                    generateSOAPFault(context, "Missing WS-Security Timestamp");
                    return false;
                }

                SOAPElement timestampElement = (SOAPElement) timestamps.next();

                String createdStr = extractTimestampValue(timestampElement, "Created");
                String expiresStr = extractTimestampValue(timestampElement, "Expires");
                String timestampId = extractTimestampId(timestampElement);

                System.out.println("WS-Security Timestamp received - Created: " + createdStr
                        + ", Expires: " + expiresStr + ", Id: " + timestampId);

                if (createdStr == null || createdStr.trim().isEmpty()) {
                    System.err.println("WS-Security: Created timestamp is missing");
                    generateSOAPFault(context, "Missing Created timestamp value");
                    return false;
                }

                Date createdDate = parseTimestamp(createdStr);
                Date expiresDate = (expiresStr != null && !expiresStr.trim().isEmpty())
                        ? parseTimestamp(expiresStr) : null;
                Date now = new Date();

                if (createdDate == null) {
                    System.err.println("WS-Security: Unable to parse Created timestamp: " + createdStr);
                    generateSOAPFault(context, "Invalid Created timestamp format");
                    return false;
                }

                // Check if created timestamp is in the future (with tolerance)
                if (createdDate.getTime() > now.getTime() + TIMESTAMP_TOLERANCE_MS) {
                    System.err.println("WS-Security: Created timestamp is in the future");
                    generateSOAPFault(context, "Timestamp Created is in the future");
                    return false;
                }

                // Check if created timestamp is too old
                if (now.getTime() - createdDate.getTime() > TIMESTAMP_TOLERANCE_MS) {
                    System.err.println("WS-Security: Created timestamp is too old (possible replay attack)");
                    generateSOAPFault(context, "Timestamp has expired - possible replay attack");
                    return false;
                }

                // Check expires if present
                if (expiresDate != null && now.after(expiresDate)) {
                    System.err.println("WS-Security: Message has expired");
                    generateSOAPFault(context, "Message timestamp has expired");
                    return false;
                }

                // Replay detection using timestamp + id combination
                String replayKey = createdStr + "|" + (timestampId != null ? timestampId : "");
                if (processedTimestamps.contains(replayKey)) {
                    System.err.println("WS-Security: Replay attack detected! Duplicate timestamp: " + replayKey);
                    generateSOAPFault(context, "Replay attack detected - duplicate message timestamp");
                    return false;
                }

                // Add to processed set with bounded cache
                processedTimestamps.add(replayKey);
                timestampQueue.add(replayKey);
                while (timestampQueue.size() > MAX_NONCE_CACHE_SIZE) {
                    String oldest = timestampQueue.poll();
                    if (oldest != null) {
                        processedTimestamps.remove(oldest);
                    }
                }

                System.out.println("WS-Security: Timestamp validation passed for: " + replayKey);
                return true;

            } catch (SOAPException e) {
                System.err.println("WS-Security: Error processing SOAP message: " + e.getMessage());
                return false;
            }
        }

        private String extractTimestampValue(SOAPElement timestampElement, String localName) {
            try {
                Iterator<?> children = timestampElement.getChildElements(new QName(WSU_NS, localName));
                if (children.hasNext()) {
                    SOAPElement element = (SOAPElement) children.next();
                    return element.getTextContent();
                }
            } catch (Exception e) {
                System.err.println("Error extracting timestamp value for " + localName + ": " + e.getMessage());
            }
            return null;
        }

        private String extractTimestampId(SOAPElement timestampElement) {
            try {
                return timestampElement.getAttributeValue(new QName(WSU_NS, "Id"));
            } catch (Exception e) {
                return null;
            }
        }

        private Date parseTimestamp(String timestampStr) {
            if (timestampStr == null) return null;
            timestampStr = timestampStr.trim();

            try {
                synchronized (ISO_FORMAT) {
                    return ISO_FORMAT.parse(timestampStr);
                }
            } catch (Exception e1) {
                try {
                    synchronized (ISO_FORMAT_NO_MILLIS) {
                        return ISO_FORMAT_NO_MILLIS.parse(timestampStr);
                    }
                } catch (Exception e2) {
                    System.err.println("Failed to parse timestamp: " + timestampStr);
                    return null;
                }
            }
        }

        private void generateSOAPFault(SOAPMessageContext context, String faultMessage) {
            try {
                SOAPMessage message = context.getMessage();
                SOAPBody body = message.getSOAPPart().getEnvelope().getBody();
                body.removeContents();
                SOAPFault fault = body.addFault();
                fault.setFaultCode(new QName("http://schemas.xmlsoap.org/soap/envelope/", "Client"));
                fault.setFaultString("WS-Security Validation Failed: " + faultMessage);
                message.saveChanges();
            } catch (SOAPException e) {
                System.err.println("Error generating SOAP fault: " + e.getMessage());
            }
        }

        @Override
        public boolean handleFault(SOAPMessageContext context) {
            System.err.println("WS-Security Handler: SOAP Fault occurred");
            return true;
        }

        @Override
        public void close(MessageContext context) {
            // cleanup if needed
        }
    }

    // --- Handler Resolver ---

    public static class PaymentHandlerResolver implements HandlerResolver {
        @Override
        public List<Handler> getHandlerChain(PortInfo portInfo) {
            List<Handler> handlerChain = new ArrayList<>();
            handlerChain.add(new WsSecurityTimestampHandler());
            return handlerChain;
        }
    }

