    public static void main(String[] args) {
        String address = "http://localhost:8080/payment-gateway";

        Endpoint endpoint = Endpoint.create(new PaymentGatewayService());

        // Attach the handler resolver for WS-Security
        endpoint.getBinding().getHandlerChain().add(new WsSecurityTimestampHandler());
        List<Handler> handlerChain = endpoint.getBinding().getHandlerChain();
        handlerChain.add(new WsSecurityTimestampHandler());
        endpoint.getBinding().setHandlerChain(handlerChain);

        endpoint.publish(address);

        System.out.println("==============================================");
        System.out.println("Payment Gateway Service started");
        System.out.println("Endpoint: " + address);
        System.out.println("WSDL:     " + address + "?wsdl");
        System.out.println("WS-Security: Timestamp tokens enabled");
        System.out.println("Replay protection: Active (5 min window)");
        System.out.println("==============================================");

        // Keep running
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down Payment Gateway Service...");
            endpoint.stop();
        }));
    }
